+/// Return true if X != Y can be inferred from a dominating branch condition.
+static bool isKnownNonEqualFromDominatingBranch(Value *X, Value *Y,
+                                                const SimplifyQuery &Q) {
+  if (!Q.DT || !Q.CxtI)
+    return false;
+  BasicBlock *CurrentBB = Q.CxtI->getParent();
+  // If there is a single predecessor, check its terminator.
+  if (BasicBlock *Pred = CurrentBB->getSinglePredecessor()) {
+    if (auto *BI = dyn_cast<BranchInst>(Pred->getTerminator())) {
+      if (BI->isConditional()) {
+        Value *Cond = BI->getCondition();
+        ICmpInst *Cmp = dyn_cast<ICmpInst>(Cond);
+        if (!Cmp)
+          return false;
+        ICmpInst::Predicate Pred = Cmp->getPredicate();
+        Value *Op0 = Cmp->getOperand(0);
+        Value *Op1 = Cmp->getOperand(1);
+        bool IsEquality = (Op0 == X && Op1 == Y) || (Op0 == Y && Op1 == X);
+        if (!IsEquality)
+          return false;
+        // Determine which edge leads to CurrentBB.
+        bool TrueEdge = (BI->getSuccessor(0) == CurrentBB);
+        // If we are on the true edge, condition is true.
+        // If we are on the false edge, condition is false (inverted predicate).
+        if (TrueEdge) {
+          // Condition true.
+          if (Pred == ICmpInst::ICMP_NE)
+            return true;
+          // For EQ, true edge means X == Y, not needed.
+        } else {
+          // Condition false.
+          if (Pred == ICmpInst::ICMP_EQ)
+            return true;
+          // For NE, false edge means X == Y.
+        }
+      }
+    }
+  }
+  return false;
+}
 /// Try hard to fold icmp with zero RHS because this is a common case.
 static Value *simplifyICmpWithZero(CmpPredicate Pred, Value *LHS, Value *RHS,
                                    const SimplifyQuery &Q) {
@@ -2933,15 +2973,33 @@ static Value *simplifyICmpWithZero(CmpPredicate Pred, Value *LHS, Value *RHS,
   case ICmpInst::ICMP_UGE:
