+    // (or X, Y) == 0 is false if X != Y.
+    Value *X, *Y;
+    if (match(LHS, m_Or(m_Value(X), m_Value(Y))) && (isKnownNonEqual(X, Y, Q) || isKnownNonEqualFromDominatingBranch(X, Y, Q))) {
+#ifndef NDEBUG
