   145 | static Value *handleOtherCmpSelSimplifications(Value *TCmp, Value *FCmp,
   146 |                                                Value *Cond,
   147 |                                                const SimplifyQuery &Q,
   148 |                                                unsigned MaxRecurse) {
   149 |   // If the false value simplified to false, then the result of the compare
