   151 |   // value simplified to false and the true value to true, returning "Cond".
   152 |   // Folding select to and/or isn't poison-safe in general; impliesPoison
   153 |   // checks whether folding it does not convert a well-defined value into
   154 |   // poison.
   155 |   if (match(FCmp, m_Zero()) && impliesPoison(TCmp, Cond))
   156 |     if (Value *V = simplifyAndInst(Cond, TCmp, Q, MaxRecurse))
   157 |       return V;
   158 |   // If the true value simplified to true, then the result of the compare
   159 |   // is equal to "Cond || FCmp".
   160 |   if (match(TCmp, m_One()) && impliesPoison(FCmp, Cond))
   161 |     if (Value *V = simplifyOrInst(Cond, FCmp, Q, MaxRecurse))
   162 |       return V;
   163 |   // Finally, if the false value simplified to true and the true value to
   164 |   // false, then the result of the compare is equal to "!Cond".
   165 |   if (match(FCmp, m_One()) && match(TCmp, m_Zero()))
   166 |     if (Value *V = simplifyXorInst(
   167 |             Cond, Constant::getAllOnesValue(Cond->getType()), Q, MaxRecurse))
   168 |       return V;
   169 |   return nullptr;
   170 | }
