   347 | /// In the case of a binary operation with a select instruction as an operand,
   348 | /// try to simplify the binop by seeing whether evaluating it on both branches
   349 | /// of the select results in the same value. Returns the common value if so,
   350 | /// otherwise returns null.
   351 | static Value *threadBinOpOverSelect(Instruction::BinaryOps Opcode, Value *LHS,
   352 |                                     Value *RHS, const SimplifyQuery &Q,
   353 |                                     unsigned MaxRecurse) {
   354 |   // Recursion is always used, so bail out at once if we already hit the limit.
   355 |   if (!MaxRecurse--)
   356 |     return nullptr;
   357 | 
   358 |   SelectInst *SI;
   359 |   if (isa<SelectInst>(LHS)) {
   360 |     SI = cast<SelectInst>(LHS);
   361 |   } else {
   362 |     assert(isa<SelectInst>(RHS) && "No select instruction operand!");
   363 |     SI = cast<SelectInst>(RHS);
   364 |   }
   365 | 
   366 |   // Evaluate the BinOp on the true and false branches of the select.
   367 |   Value *TV;
   368 |   Value *FV;
   369 |   if (SI == LHS) {
   370 |     TV = simplifyBinOp(Opcode, SI->getTrueValue(), RHS, Q, MaxRecurse);
   371 |     FV = simplifyBinOp(Opcode, SI->getFalseValue(), RHS, Q, MaxRecurse);
   372 |   } else {
   373 |     TV = simplifyBinOp(Opcode, LHS, SI->getTrueValue(), Q, MaxRecurse);
   374 |     FV = simplifyBinOp(Opcode, LHS, SI->getFalseValue(), Q, MaxRecurse);
   375 |   }
   376 | 
   377 |   // If they simplified to the same value, then return the common value.
   378 |   // If they both failed to simplify then return null.
   379 |   if (TV == FV)
   380 |     return TV;
   381 | 
   382 |   // If one branch simplified to undef, return the other one.
   383 |   if (TV && Q.isUndefValue(TV))
   384 |     return FV;
   385 |   if (FV && Q.isUndefValue(FV))
   386 |     return TV;
   387 | 
   388 |   // If applying the operation did not change the true and false select values,
   389 |   // then the result of the binop is the select itself.
   390 |   if (TV == SI->getTrueValue() && FV == SI->getFalseValue())
   391 |     return SI;
   392 | 
   393 |   // If one branch simplified and the other did not, and the simplified
   394 |   // value is equal to the unsimplified one, return the simplified value.
   395 |   // For example, select (cond, X, X & Z) & Z -> X & Z.
   396 |   if ((FV && !TV) || (TV && !FV)) {
   397 |     // Check that the simplified value has the form "X op Y" where "op" is the
   398 |     // same as the original operation.
   399 |     Instruction *Simplified = dyn_cast<Instruction>(FV ? FV : TV);
   400 |     if (Simplified && Simplified->getOpcode() == unsigned(Opcode) &&
   401 |         !Simplified->hasPoisonGeneratingFlags()) {
   402 |       // The value that didn't simplify is "UnsimplifiedLHS op UnsimplifiedRHS".
   403 |       // We already know that "op" is the same as for the simplified value.  See
   404 |       // if the operands match too.  If so, return the simplified value.
   405 |       Value *UnsimplifiedBranch = FV ? SI->getTrueValue() : SI->getFalseValue();
   406 |       Value *UnsimplifiedLHS = SI == LHS ? UnsimplifiedBranch : LHS;
   407 |       Value *UnsimplifiedRHS = SI == LHS ? RHS : UnsimplifiedBranch;
   408 |       if (Simplified->getOperand(0) == UnsimplifiedLHS &&
   409 |           Simplified->getOperand(1) == UnsimplifiedRHS)
   410 |         return Simplified;
   411 |       if (Simplified->isCommutative() &&
   412 |           Simplified->getOperand(1) == UnsimplifiedLHS &&
   413 |           Simplified->getOperand(0) == UnsimplifiedRHS)
   414 |         return Simplified;
   415 |     }
   416 |   }
   417 | 
   418 |   return nullptr;
   419 | }
