   421 | /// In the case of a comparison with a select instruction, try to simplify the
   422 | /// comparison by seeing whether both branches of the select result in the same
   423 | /// value. Returns the common value if so, otherwise returns null.
   424 | /// For example, if we have:
   425 | ///  %tmp = select i1 %cmp, i32 1, i32 2
   426 | ///  %cmp1 = icmp sle i32 %tmp, 3
   427 | /// We can simplify %cmp1 to true, because both branches of select are
   428 | /// less than 3. We compose new comparison by substituting %tmp with both
   429 | /// branches of select and see if it can be simplified.
   430 | static Value *threadCmpOverSelect(CmpPredicate Pred, Value *LHS, Value *RHS,
   431 |                                   const SimplifyQuery &Q, unsigned MaxRecurse) {
   432 |   // Recursion is always used, so bail out at once if we already hit the limit.
   433 |   if (!MaxRecurse--)
   434 |     return nullptr;
   435 | 
   436 |   // Make sure the select is on the LHS.
   437 |   if (!isa<SelectInst>(LHS)) {
   438 |     std::swap(LHS, RHS);
   439 |     Pred = CmpInst::getSwappedPredicate(Pred);
   440 |   }
   441 |   assert(isa<SelectInst>(LHS) && "Not comparing with a select instruction!");
   442 |   SelectInst *SI = cast<SelectInst>(LHS);
   443 |   Value *Cond = SI->getCondition();
   444 |   Value *TV = SI->getTrueValue();
   445 |   Value *FV = SI->getFalseValue();
   446 | 
   447 |   // Now that we have "cmp select(Cond, TV, FV), RHS", analyse it.
   448 |   // Does "cmp TV, RHS" simplify?
   449 |   Value *TCmp = simplifyCmpSelTrueCase(Pred, TV, RHS, Cond, Q, MaxRecurse);
   450 |   if (!TCmp)
   451 |     return nullptr;
   452 | 
   453 |   // Does "cmp FV, RHS" simplify?
   454 |   Value *FCmp = simplifyCmpSelFalseCase(Pred, FV, RHS, Cond, Q, MaxRecurse);
   455 |   if (!FCmp)
   456 |     return nullptr;
   457 | 
   458 |   // If both sides simplified to the same value, then use it as the result of
   459 |   // the original comparison.
   460 |   if (TCmp == FCmp)
   461 |     return TCmp;
   462 | 
   463 |   // The remaining cases only make sense if the select condition has the same
   464 |   // type as the result of the comparison, so bail out if this is not so.
   465 |   if (Cond->getType()->isVectorTy() == RHS->getType()->isVectorTy())
   466 |     return handleOtherCmpSelSimplifications(TCmp, FCmp, Cond, Q, MaxRecurse);
   467 | 
   468 |   return nullptr;
   469 | }
