   471 | /// In the case of a binary operation with an operand that is a PHI instruction,
   472 | /// try to simplify the binop by seeing whether evaluating it on the incoming
   473 | /// phi values yields the same result for every value. If so returns the common
   474 | /// value, otherwise returns null.
   475 | static Value *threadBinOpOverPHI(Instruction::BinaryOps Opcode, Value *LHS,
   476 |                                  Value *RHS, const SimplifyQuery &Q,
   477 |                                  unsigned MaxRecurse) {
   478 |   // Recursion is always used, so bail out at once if we already hit the limit.
   479 |   if (!MaxRecurse--)
   480 |     return nullptr;
   481 | 
   482 |   PHINode *PI;
   483 |   if (isa<PHINode>(LHS)) {
   484 |     PI = cast<PHINode>(LHS);
   485 |     // Bail out if RHS and the phi may be mutually interdependent due to a loop.
   486 |     if (!valueDominatesPHI(RHS, PI, Q.DT))
   487 |       return nullptr;
   488 |   } else {
   489 |     assert(isa<PHINode>(RHS) && "No PHI instruction operand!");
   490 |     PI = cast<PHINode>(RHS);
   491 |     // Bail out if LHS and the phi may be mutually interdependent due to a loop.
   492 |     if (!valueDominatesPHI(LHS, PI, Q.DT))
   493 |       return nullptr;
   494 |   }
   495 | 
   496 |   // Evaluate the BinOp on the incoming phi values.
   497 |   Value *CommonValue = nullptr;
   498 |   for (Use &Incoming : PI->incoming_values()) {
   499 |     // If the incoming value is the phi node itself, it can safely be skipped.
   500 |     if (Incoming == PI)
   501 |       continue;
   502 |     Instruction *InTI = PI->getIncomingBlock(Incoming)->getTerminator();
   503 |     Value *V = PI == LHS
   504 |                    ? simplifyBinOp(Opcode, Incoming, RHS,
   505 |                                    Q.getWithInstruction(InTI), MaxRecurse)
   506 |                    : simplifyBinOp(Opcode, LHS, Incoming,
   507 |                                    Q.getWithInstruction(InTI), MaxRecurse);
   508 |     // If the operation failed to simplify, or simplified to a different value
   509 |     // to previously, then give up.
   510 |     if (!V || (CommonValue && V != CommonValue))
   511 |       return nullptr;
   512 |     CommonValue = V;
   513 |   }
   514 | 
   515 |   return CommonValue;
   516 | }
   517 | 
   518 | /// In the case of a comparison with a PHI instruction, try to simplify the
   519 | /// comparison by seeing whether comparing with all of the incoming phi values
   520 | /// yields the same result every time. If so returns the common result,
   521 | /// otherwise returns null.
   522 | static Value *threadCmpOverPHI(CmpPredicate Pred, Value *LHS, Value *RHS,
   523 |                                const SimplifyQuery &Q, unsigned MaxRecurse) {
   524 |   // Recursion is always used, so bail out at once if we already hit the limit.
   525 |   if (!MaxRecurse--)
   526 |     return nullptr;
   527 | 
   528 |   // Make sure the phi is on the LHS.
   529 |   if (!isa<PHINode>(LHS)) {
   530 |     std::swap(LHS, RHS);
   531 |     Pred = CmpInst::getSwappedPredicate(Pred);
   532 |   }
   533 |   assert(isa<PHINode>(LHS) && "Not comparing with a phi instruction!");
   534 |   PHINode *PI = cast<PHINode>(LHS);
   535 | 
   536 |   // Bail out if RHS and the phi may be mutually interdependent due to a loop.
   537 |   if (!valueDominatesPHI(RHS, PI, Q.DT))
   538 |     return nullptr;
   539 | 
   540 |   // Evaluate the BinOp on the incoming phi values.
   541 |   Value *CommonValue = nullptr;
   542 |   for (unsigned u = 0, e = PI->getNumIncomingValues(); u < e; ++u) {
   543 |     Value *Incoming = PI->getIncomingValue(u);
   544 |     Instruction *InTI = PI->getIncomingBlock(u)->getTerminator();
   545 |     // If the incoming value is the phi node itself, it can safely be skipped.
   546 |     if (Incoming == PI)
   547 |       continue;
   548 |     // Change the context instruction to the "edge" that flows into the phi.
   549 |     // This is important because that is where incoming is actually "evaluated"
   550 |     // even though it is used later somewhere else.
   551 |     Value *V = simplifyCmpInst(Pred, Incoming, RHS, Q.getWithInstruction(InTI),
   552 |                                MaxRecurse);
   553 |     // If the operation failed to simplify, or simplified to a different value
   554 |     // to previously, then give up.
   555 |     if (!V || (CommonValue && V != CommonValue))
   556 |       return nullptr;
   557 |     CommonValue = V;
   558 |   }
   559 | 
   560 |   return CommonValue;
   561 | }
