   563 | static Constant *foldOrCommuteConstant(Instruction::BinaryOps Opcode,
   564 |                                        Value *&Op0, Value *&Op1,
   565 |                                        const SimplifyQuery &Q) {
   566 |   if (auto *CLHS = dyn_cast<Constant>(Op0)) {
   567 |     if (auto *CRHS = dyn_cast<Constant>(Op1)) {
   568 |       switch (Opcode) {
   569 |       default:
   570 |         break;
   571 |       case Instruction::FAdd:
   572 |       case Instruction::FSub:
   573 |       case Instruction::FMul:
   574 |       case Instruction::FDiv:
   575 |       case Instruction::FRem:
   576 |         if (Q.CxtI != nullptr)
   577 |           return ConstantFoldFPInstOperands(Opcode, CLHS, CRHS, Q.DL, Q.CxtI);
   578 |       }
   579 |       return ConstantFoldBinaryOpOperands(Opcode, CLHS, CRHS, Q.DL);
   580 |     }
   581 | 
   582 |     // Canonicalize the constant to the RHS if this is a commutative operation.
   583 |     if (Instruction::isCommutative(Opcode))
   584 |       std::swap(Op0, Op1);
   585 |   }
   586 |   return nullptr;
   587 | }
