   589 | /// Given operands for an Add, see if we can fold the result.
   590 | /// If not, this returns null.
   591 | static Value *simplifyAddInst(Value *Op0, Value *Op1, bool IsNSW, bool IsNUW,
   592 |                               const SimplifyQuery &Q, unsigned MaxRecurse) {
   593 |   if (Constant *C = foldOrCommuteConstant(Instruction::Add, Op0, Op1, Q))
   594 |     return C;
   595 | 
   596 |   // X + poison -> poison
   597 |   if (isa<PoisonValue>(Op1))
   598 |     return Op1;
   599 | 
   600 |   // X + undef -> undef
   601 |   if (Q.isUndefValue(Op1))
   602 |     return Op1;
   603 | 
   604 |   // X + 0 -> X
   605 |   if (match(Op1, m_Zero()))
   606 |     return Op0;
   607 | 
   608 |   // If two operands are negative, return 0.
   609 |   if (isKnownNegation(Op0, Op1))
   610 |     return Constant::getNullValue(Op0->getType());
   611 | 
   612 |   // X + (Y - X) -> Y
   613 |   // (Y - X) + X -> Y
   614 |   // Eg: X + -X -> 0
   615 |   Value *Y = nullptr;
   616 |   if (match(Op1, m_Sub(m_Value(Y), m_Specific(Op0))) ||
   617 |       match(Op0, m_Sub(m_Value(Y), m_Specific(Op1))))
   618 |     return Y;
   619 | 
   620 |   // X + ~X -> -1   since   ~X = -X-1
   621 |   Type *Ty = Op0->getType();
   622 |   if (match(Op0, m_Not(m_Specific(Op1))) || match(Op1, m_Not(m_Specific(Op0))))
   623 |     return Constant::getAllOnesValue(Ty);
   624 | 
   625 |   // add nsw/nuw (xor Y, signmask), signmask --> Y
   626 |   // The no-wrapping add guarantees that the top bit will be set by the add.
   627 |   // Therefore, the xor must be clearing the already set sign bit of Y.
   628 |   if ((IsNSW || IsNUW) && match(Op1, m_SignMask()) &&
   629 |       match(Op0, m_Xor(m_Value(Y), m_SignMask())))
   630 |     return Y;
   631 | 
   632 |   // add nuw %x, -1  ->  -1, because %x can only be 0.
   633 |   if (IsNUW && match(Op1, m_AllOnes()))
   634 |     return Op1; // Which is -1.
   635 | 
   636 |   /// i1 add -> xor.
   637 |   if (MaxRecurse && Op0->getType()->isIntOrIntVectorTy(1))
   638 |     if (Value *V = simplifyXorInst(Op0, Op1, Q, MaxRecurse - 1))
   639 |       return V;
   640 | 
   641 |   // Try some generic simplifications for associative operations.
   642 |   if (Value *V =
   643 |           simplifyAssociativeBinOp(Instruction::Add, Op0, Op1, Q, MaxRecurse))
   644 |     return V;
   645 | 
   646 |   // Threading Add over selects and phi nodes is pointless, so don't bother.
   647 |   // Threading over the select in "A + select(cond, B, C)" means evaluating
   648 |   // "A+B" and "A+C" and seeing if they are equal; but they are equal if and
   649 |   // only if B and C are equal.  If B and C are equal then (since we assume
   650 |   // that operands have already been simplified) "select(cond, B, C)" should
   651 |   // have been simplified to the common value of B and C already.  Analysing
   652 |   // "A+B" and "A+C" thus gains nothing, but costs compile time.  Similarly
   653 |   // for threading over phi nodes.
   654 | 
   655 |   return nullptr;
   656 | }
