   663 | /// Compute the base pointer and cumulative constant offsets for V.
   664 | ///
   665 | /// This strips all constant offsets off of V, leaving it the base pointer, and
   666 | /// accumulates the total constant offset applied in the returned constant.
   667 | /// It returns zero if there are no constant offsets applied.
   668 | ///
   669 | /// This is very similar to stripAndAccumulateConstantOffsets(), except it
   670 | /// normalizes the offset bitwidth to the stripped pointer type, not the
   671 | /// original pointer type.
   672 | static APInt stripAndComputeConstantOffsets(const DataLayout &DL, Value *&V,
   673 |                                             bool AllowNonInbounds = false) {
   674 |   assert(V->getType()->isPtrOrPtrVectorTy());
   675 | 
   676 |   APInt Offset = APInt::getZero(DL.getIndexTypeSizeInBits(V->getType()));
   677 |   V = V->stripAndAccumulateConstantOffsets(DL, Offset, AllowNonInbounds);
   678 |   // As that strip may trace through `addrspacecast`, need to sext or trunc
   679 |   // the offset calculated.
   680 |   return Offset.sextOrTrunc(DL.getIndexTypeSizeInBits(V->getType()));
   681 | }
   682 | 
   683 | /// Compute the constant difference between two pointer values.
   684 | /// If the difference is not a constant, returns zero.
   685 | static Constant *computePointerDifference(const DataLayout &DL, Value *LHS,
   686 |                                           Value *RHS) {
   687 |   APInt LHSOffset = stripAndComputeConstantOffsets(DL, LHS);
   688 |   APInt RHSOffset = stripAndComputeConstantOffsets(DL, RHS);
   689 | 
   690 |   // If LHS and RHS are not related via constant offsets to the same base
   691 |   // value, there is nothing we can do here.
   692 |   if (LHS != RHS)
   693 |     return nullptr;
   694 | 
   695 |   // Otherwise, the difference of LHS - RHS can be computed as:
   696 |   //    LHS - RHS
   697 |   //  = (LHSOffset + Base) - (RHSOffset + Base)
   698 |   //  = LHSOffset - RHSOffset
   699 |   Constant *Res = ConstantInt::get(LHS->getContext(), LHSOffset - RHSOffset);
   700 |   if (auto *VecTy = dyn_cast<VectorType>(LHS->getType()))
   701 |     Res = ConstantVector::getSplat(VecTy->getElementCount(), Res);
   702 |   return Res;
   703 | }
   704 | 
   705 | /// Test if there is a dominating equivalence condition for the
   706 | /// two operands. If there is, try to reduce the binary operation
   707 | /// between the two operands.
   708 | /// Example: Op0 - Op1 --> 0 when Op0 == Op1
   709 | static Value *simplifyByDomEq(unsigned Opcode, Value *Op0, Value *Op1,
   710 |                               const SimplifyQuery &Q, unsigned MaxRecurse) {
   711 |   // Recursive run it can not get any benefit
   712 |   if (MaxRecurse != RecursionLimit)
   713 |     return nullptr;
   714 | 
   715 |   std::optional<bool> Imp =
   716 |       isImpliedByDomCondition(CmpInst::ICMP_EQ, Op0, Op1, Q.CxtI, Q.DL);
   717 |   if (Imp && *Imp) {
   718 |     Type *Ty = Op0->getType();
   719 |     switch (Opcode) {
   720 |     case Instruction::Sub:
   721 |     case Instruction::Xor:
   722 |     case Instruction::URem:
   723 |     case Instruction::SRem:
   724 |       return Constant::getNullValue(Ty);
   725 | 
   726 |     case Instruction::SDiv:
   727 |     case Instruction::UDiv:
   728 |       return ConstantInt::get(Ty, 1);
   729 | 
   730 |     case Instruction::And:
   731 |     case Instruction::Or:
   732 |       // Could be either one - choose Op1 since that's more likely a constant.
   733 |       return Op1;
   734 |     default:
   735 |       break;
   736 |     }
   737 |   }
   738 |   return nullptr;
   739 | }
