   741 | /// Given operands for a Sub, see if we can fold the result.
   742 | /// If not, this returns null.
   743 | static Value *simplifySubInst(Value *Op0, Value *Op1, bool IsNSW, bool IsNUW,
   744 |                               const SimplifyQuery &Q, unsigned MaxRecurse) {
   745 |   if (Constant *C = foldOrCommuteConstant(Instruction::Sub, Op0, Op1, Q))
   746 |     return C;
   747 | 
   748 |   // X - poison -> poison
   749 |   // poison - X -> poison
   750 |   if (isa<PoisonValue>(Op0) || isa<PoisonValue>(Op1))
   751 |     return PoisonValue::get(Op0->getType());
   752 | 
   753 |   // X - undef -> undef
   754 |   // undef - X -> undef
   755 |   if (Q.isUndefValue(Op0) || Q.isUndefValue(Op1))
   756 |     return UndefValue::get(Op0->getType());
   757 | 
   758 |   // X - 0 -> X
   759 |   if (match(Op1, m_Zero()))
   760 |     return Op0;
   761 | 
   762 |   // X - X -> 0
   763 |   if (Op0 == Op1)
   764 |     return Constant::getNullValue(Op0->getType());
   765 | 
   766 |   // Is this a negation?
   767 |   if (match(Op0, m_Zero())) {
   768 |     // 0 - X -> 0 if the sub is NUW.
   769 |     if (IsNUW)
   770 |       return Constant::getNullValue(Op0->getType());
   771 | 
   772 |     KnownBits Known = computeKnownBits(Op1, /* Depth */ 0, Q);
   773 |     if (Known.Zero.isMaxSignedValue()) {
   774 |       // Op1 is either 0 or the minimum signed value. If the sub is NSW, then
   775 |       // Op1 must be 0 because negating the minimum signed value is undefined.
   776 |       if (IsNSW)
   777 |         return Constant::getNullValue(Op0->getType());
   778 | 
   779 |       // 0 - X -> X if X is 0 or the minimum signed value.
   780 |       return Op1;
   781 |     }
   782 |   }
   783 | 
   784 |   // (X + Y) - Z -> X + (Y - Z) or Y + (X - Z) if everything simplifies.
   785 |   // For example, (X + Y) - Y -> X; (Y + X) - Y -> X
   786 |   Value *X = nullptr, *Y = nullptr, *Z = Op1;
   787 |   if (MaxRecurse && match(Op0, m_Add(m_Value(X), m_Value(Y)))) { // (X + Y) - Z
   788 |     // See if "V === Y - Z" simplifies.
   789 |     if (Value *V = simplifyBinOp(Instruction::Sub, Y, Z, Q, MaxRecurse - 1))
   790 |       // It does!  Now see if "X + V" simplifies.
   791 |       if (Value *W = simplifyBinOp(Instruction::Add, X, V, Q, MaxRecurse - 1)) {
   792 |         // It does, we successfully reassociated!
   793 |         ++NumReassoc;
   794 |         return W;
   795 |       }
   796 |     // See if "V === X - Z" simplifies.
   797 |     if (Value *V = simplifyBinOp(Instruction::Sub, X, Z, Q, MaxRecurse - 1))
   798 |       // It does!  Now see if "Y + V" simplifies.
   799 |       if (Value *W = simplifyBinOp(Instruction::Add, Y, V, Q, MaxRecurse - 1)) {
   800 |         // It does, we successfully reassociated!
   801 |         ++NumReassoc;
   802 |         return W;
   803 |       }
   804 |   }
   805 | 
   806 |   // X - (Y + Z) -> (X - Y) - Z or (X - Z) - Y if everything simplifies.
   807 |   // For example, X - (X + 1) -> -1
   808 |   X = Op0;
   809 |   if (MaxRecurse && match(Op1, m_Add(m_Value(Y), m_Value(Z)))) { // X - (Y + Z)
   810 |     // See if "V === X - Y" simplifies.
   811 |     if (Value *V = simplifyBinOp(Instruction::Sub, X, Y, Q, MaxRecurse - 1))
   812 |       // It does!  Now see if "V - Z" simplifies.
   813 |       if (Value *W = simplifyBinOp(Instruction::Sub, V, Z, Q, MaxRecurse - 1)) {
   814 |         // It does, we successfully reassociated!
   815 |         ++NumReassoc;
   816 |         return W;
   817 |       }
   818 |     // See if "V === X - Z" simplifies.
   819 |     if (Value *V = simplifyBinOp(Instruction::Sub, X, Z, Q, MaxRecurse - 1))
   820 |       // It does!  Now see if "V - Y" simplifies.
   821 |       if (Value *W = simplifyBinOp(Instruction::Sub, V, Y, Q, MaxRecurse - 1)) {
   822 |         // It does, we successfully reassociated!
   823 |         ++NumReassoc;
   824 |         return W;
   825 |       }
   826 |   }
   827 | 
   828 |   // Z - (X - Y) -> (Z - X) + Y if everything simplifies.
   829 |   // For example, X - (X - Y) -> Y.
   830 |   Z = Op0;
   831 |   if (MaxRecurse && match(Op1, m_Sub(m_Value(X), m_Value(Y)))) // Z - (X - Y)
   832 |     // See if "V === Z - X" simplifies.
   833 |     if (Value *V = simplifyBinOp(Instruction::Sub, Z, X, Q, MaxRecurse - 1))
   834 |       // It does!  Now see if "V + Y" simplifies.
   835 |       if (Value *W = simplifyBinOp(Instruction::Add, V, Y, Q, MaxRecurse - 1)) {
   836 |         // It does, we successfully reassociated!
   837 |         ++NumReassoc;
   838 |         return W;
   839 |       }
   840 | 
   841 |   // trunc(X) - trunc(Y) -> trunc(X - Y) if everything simplifies.
   842 |   if (MaxRecurse && match(Op0, m_Trunc(m_Value(X))) &&
   843 |       match(Op1, m_Trunc(m_Value(Y))))
   844 |     if (X->getType() == Y->getType())
   845 |       // See if "V === X - Y" simplifies.
   846 |       if (Value *V = simplifyBinOp(Instruction::Sub, X, Y, Q, MaxRecurse - 1))
   847 |         // It does!  Now see if "trunc V" simplifies.
   848 |         if (Value *W = simplifyCastInst(Instruction::Trunc, V, Op0->getType(),
   849 |                                         Q, MaxRecurse - 1))
   850 |           // It does, return the simplified "trunc V".
   851 |           return W;
   852 | 
   853 |   // Variations on GEP(base, I, ...) - GEP(base, i, ...) -> GEP(null, I-i, ...).
   854 |   if (match(Op0, m_PtrToInt(m_Value(X))) && match(Op1, m_PtrToInt(m_Value(Y))))
   855 |     if (Constant *Result = computePointerDifference(Q.DL, X, Y))
   856 |       return ConstantFoldIntegerCast(Result, Op0->getType(), /*IsSigned*/ true,
   857 |                                      Q.DL);
   858 | 
   859 |   // i1 sub -> xor.
   860 |   if (MaxRecurse && Op0->getType()->isIntOrIntVectorTy(1))
   861 |     if (Value *V = simplifyXorInst(Op0, Op1, Q, MaxRecurse - 1))
   862 |       return V;
   863 | 
   864 |   // Threading Sub over selects and phi nodes is pointless, so don't bother.
   865 |   // Threading over the select in "A - select(cond, B, C)" means evaluating
   866 |   // "A-B" and "A-C" and seeing if they are equal; but they are equal if and
   867 |   // only if B and C are equal.  If B and C are equal then (since we assume
   868 |   // that operands have already been simplified) "select(cond, B, C)" should
   869 |   // have been simplified to the common value of B and C already.  Analysing
   870 |   // "A-B" and "A-C" thus gains nothing, but costs compile time.  Similarly
   871 |   // for threading over phi nodes.
   872 | 
   873 |   if (Value *V = simplifyByDomEq(Instruction::Sub, Op0, Op1, Q, MaxRecurse))
   874 |     return V;
   875 | 
   876 |   // (sub nuw C_Mask, (xor X, C_Mask)) -> X
   877 |   if (IsNUW) {
   878 |     Value *X;
   879 |     if (match(Op1, m_Xor(m_Value(X), m_Specific(Op0))) &&
   880 |         match(Op0, m_LowBitMask()))
   881 |       return X;
   882 |   }
   883 | 
   884 |   return nullptr;
   885 | }
