   892 | /// Given operands for a Mul, see if we can fold the result.
   893 | /// If not, this returns null.
   894 | static Value *simplifyMulInst(Value *Op0, Value *Op1, bool IsNSW, bool IsNUW,
   895 |                               const SimplifyQuery &Q, unsigned MaxRecurse) {
   896 |   if (Constant *C = foldOrCommuteConstant(Instruction::Mul, Op0, Op1, Q))
   897 |     return C;
   898 | 
   899 |   // X * poison -> poison
   900 |   if (isa<PoisonValue>(Op1))
   901 |     return Op1;
   902 | 
   903 |   // X * undef -> 0
   904 |   // X * 0 -> 0
   905 |   if (Q.isUndefValue(Op1) || match(Op1, m_Zero()))
   906 |     return Constant::getNullValue(Op0->getType());
   907 | 
   908 |   // X * 1 -> X
   909 |   if (match(Op1, m_One()))
   910 |     return Op0;
   911 | 
   912 |   // (X / Y) * Y -> X if the division is exact.
   913 |   Value *X = nullptr;
   914 |   if (Q.IIQ.UseInstrInfo &&
   915 |       (match(Op0,
   916 |              m_Exact(m_IDiv(m_Value(X), m_Specific(Op1)))) ||     // (X / Y) * Y
   917 |        match(Op1, m_Exact(m_IDiv(m_Value(X), m_Specific(Op0)))))) // Y * (X / Y)
   918 |     return X;
   919 | 
   920 |    if (Op0->getType()->isIntOrIntVectorTy(1)) {
   921 |     // mul i1 nsw is a special-case because -1 * -1 is poison (+1 is not
   922 |     // representable). All other cases reduce to 0, so just return 0.
   923 |     if (IsNSW)
   924 |       return ConstantInt::getNullValue(Op0->getType());
   925 | 
   926 |     // Treat "mul i1" as "and i1".
   927 |     if (MaxRecurse)
   928 |       if (Value *V = simplifyAndInst(Op0, Op1, Q, MaxRecurse - 1))
   929 |         return V;
   930 |   }
   931 | 
   932 |   // Try some generic simplifications for associative operations.
   933 |   if (Value *V =
   934 |           simplifyAssociativeBinOp(Instruction::Mul, Op0, Op1, Q, MaxRecurse))
   935 |     return V;
   936 | 
   937 |   // Mul distributes over Add. Try some generic simplifications based on this.
   938 |   if (Value *V = expandCommutativeBinOp(Instruction::Mul, Op0, Op1,
   939 |                                         Instruction::Add, Q, MaxRecurse))
   940 |     return V;
   941 | 
   942 |   // If the operation is with the result of a select instruction, check whether
   943 |   // operating on either branch of the select always yields the same value.
   944 |   if (isa<SelectInst>(Op0) || isa<SelectInst>(Op1))
   945 |     if (Value *V =
   946 |             threadBinOpOverSelect(Instruction::Mul, Op0, Op1, Q, MaxRecurse))
   947 |       return V;
   948 | 
   949 |   // If the operation is with the result of a phi instruction, check whether
   950 |   // operating on all incoming values of the phi always yields the same value.
   951 |   if (isa<PHINode>(Op0) || isa<PHINode>(Op1))
   952 |     if (Value *V =
   953 |             threadBinOpOverPHI(Instruction::Mul, Op0, Op1, Q, MaxRecurse))
   954 |       return V;
   955 | 
   956 |   return nullptr;
   957 | }
