  3863 | /// For vector constants, loop over the elements and find the constant with the
  3864 | /// minimum number of sign bits. Return 0 if the value is not a vector constant
  3865 | /// or if any element was not analyzed; otherwise, return the count for the
  3866 | /// element with the minimum number of sign bits.
  3867 | static unsigned computeNumSignBitsVectorConstant(const Value *V,
  3868 |                                                  const APInt &DemandedElts,
  3869 |                                                  unsigned TyBits) {
  3870 |   const auto *CV = dyn_cast<Constant>(V);
  3871 |   if (!CV || !isa<FixedVectorType>(CV->getType()))
  3872 |     return 0;
  3873 | 
  3874 |   unsigned MinSignBits = TyBits;
  3875 |   unsigned NumElts = cast<FixedVectorType>(CV->getType())->getNumElements();
  3876 |   for (unsigned i = 0; i != NumElts; ++i) {
  3877 |     if (!DemandedElts[i])
  3878 |       continue;
  3879 |     // If we find a non-ConstantInt, bail out.
  3880 |     auto *Elt = dyn_cast_or_null<ConstantInt>(CV->getAggregateElement(i));
  3881 |     if (!Elt)
  3882 |       return 0;
  3883 | 
  3884 |     MinSignBits = std::min(MinSignBits, Elt->getValue().getNumSignBits());
  3885 |   }
  3886 | 
  3887 |   return MinSignBits;
  3888 | }
