static bool isKnownNonEqualFromDominatingBranch(Value *X, Value *Y,
                                                const SimplifyQuery &Q) {
  if (!Q.DT || !Q.CxtI)
    return false;
  BasicBlock *CurrentBB = Q.CxtI->getParent();
  // If there is a single predecessor, check its terminator.
  if (BasicBlock *Pred = CurrentBB->getSinglePredecessor()) {
    if (auto *BI = dyn_cast<BranchInst>(Pred->getTerminator())) {
      if (BI->isConditional()) {
        Value *Cond = BI->getCondition();
        // Check if condition is icmp ne X, Y and the true edge goes to CurrentBB.
        ICmpInst *Cmp = dyn_cast<ICmpInst>(Cond);
        if (Cmp && Cmp->getPredicate() == ICmpInst::ICMP_NE &&
            ((Cmp->getOperand(0) == X && Cmp->getOperand(1) == Y) ||
             (Cmp->getOperand(0) == Y && Cmp->getOperand(1) == X))) {
          // Determine which edge leads to CurrentBB.
          if (BI->getSuccessor(0) == CurrentBB) {
            // True edge is successor 0? Actually branch condition true goes to successor 0.
            // So if condition is true, we go to successor 0.
            // Since we are in the block where the condition is true, we need to ensure that
            // the edge taken corresponds to the condition being true.
            // If the condition is NE, and we are in the true successor, then X != Y holds.
            // So we can return true.
            return true;
          } else if (BI->getSuccessor(1) == CurrentBB) {
            // If we are in the false successor, condition is false, so X == Y holds.
            // Not our case.
            return false;
          }
        }
      }
